impl<'a> MemoryUnmapInfo<'a> {
    pub fn flags(mut self, value: MemoryUnmapFlags) -> Self {
        self.flags = value;
        self
    }
    pub fn memory(mut self, value: DeviceMemory) -> Self {
        self.memory = value;
        self
    }
    pub fn push_next<T>(mut self, next: &'a mut T) -> Self
    where
        T: crate::vk::Extends<Self> + crate::vk::TaggedStructure + ?Sized,
    {
        unsafe {
            let next_ptr = next as *mut T as *mut crate::vk::PNextOutStructure;
            let mut tail = next_ptr;
            while !(*tail).p_next.is_null() {
                tail = (*tail).p_next.cast();
            }
            (*tail).p_next = self.p_next as *mut c_void;
            self.p_next = next_ptr.cast();
        }
        self
    }
}

